import Foundation

/// A namespace that provides paths for files generated by the `generate-swiftiomatic` tool.
package enum GenerateSwiftiomaticPaths {
    private static let sourcesDirectory =
        URL(fileURLWithPath: #filePath)
        .deletingLastPathComponent()
        .deletingLastPathComponent()
    package static let rulesDirectory =
        sourcesDirectory
        .appendingPathComponent("Swiftiomatic")
        .appendingPathComponent("Rules")
    package static let pipelineFile =
        sourcesDirectory
        .appendingPathComponent("Swiftiomatic")
        .appendingPathComponent("Core")
        .appendingPathComponent("Pipelines+Generated.swift")
    package static let ruleRegistryFile =
        sourcesDirectory
        .appendingPathComponent("Swiftiomatic")
        .appendingPathComponent("Core")
        .appendingPathComponent("RuleRegistry+Generated.swift")
    package static let ruleNameCacheFile =
        sourcesDirectory
        .appendingPathComponent("Swiftiomatic")
        .appendingPathComponent("Core")
        .appendingPathComponent("RuleNameCache+Generated.swift")
    package static let ruleDocumentationFile =
        sourcesDirectory
        .appendingPathComponent("..")
        .appendingPathComponent("Documentation")
        .appendingPathComponent("RuleDocumentation.md")
    package static let configurationSchemaFile =
        sourcesDirectory
        .appendingPathComponent("..")
        .appendingPathComponent("schema.json")
}
